Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class PlatformSpecificTests
{
    private readonly TestContext _testContext;

    public PlatformSpecificTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only (skipped on Linux/macOS)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuRendering_ProducesExpectedOutput()
    {
        var result = GpuRenderer.Render(scene);
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await _weatherClient.GetForecastAsync(_testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Cleanup temp files even on failure — use [TestCleanup]
    private string? _tempFile;

    [TestMethod]
    public void Export_WritesValidFile()
    {
        _tempFile = Path.GetTempFileName();

        Exporter.WriteTo(_tempFile);

        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
            File.Delete(_tempFile);
    }
}
```

**Summary of attributes:**

| Scenario | Attribute/Pattern |
|----------|------------------|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` |
| Flaky external dep | `[Retry(3)]` |
| Guaranteed cleanup | `[TestCleanup]` (runs even on failure) |

**Notes:**
- `[OSCondition]` and `[CICondition]` require MSTest 3.10+
- `[Retry]` requires MSTest 3.9+ — use only for genuinely flaky external dependencies, not to mask race conditions
- `[TestCleanup]` always runs after the test method, making it ideal for resource cleanup. Alternatively, implement `IDisposable` on the test class.
